import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';

const Availability = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('upcoming');

  // Sample appointments data based on the reference image
  const sampleAppointments = {
    upcoming: [
      {
        id: '1',
        doctor: 'Dr. Rajesh Kumar',
        specialty: 'General Medicine',
        avatar: 'DRK',
        date: 'Mon, Sep 15, 2025',
        time: '10:00',
        bookedDate: 'Sat, Sep 13, 2025',
        type: 'Consultation',
        notes: 'Regular checkup',
        status: 'Scheduled'
      },
      {
        id: '2',
        doctor: 'Dr. Priya Sharma',
        specialty: 'Cardiology',
        avatar: 'DPS',
        date: 'Thu, Sep 18, 2025',
        time: '14:30',
        bookedDate: 'Fri, Sep 12, 2025',
        type: 'Follow-up',
        notes: 'Heart condition review',
        status: 'Scheduled'
      }
    ],
    past: [
      {
        id: '3',
        doctor: 'Dr. Amit Singh',
        specialty: 'Dermatology',
        avatar: 'DAS',
        date: 'Tue, Sep 10, 2025',
        time: '11:00',
        bookedDate: 'Mon, Sep 8, 2025',
        type: 'Consultation',
        notes: 'Skin allergy consultation',
        status: 'Completed'
      }
    ],
    cancelled: []
  };

  const tabs = [
    { key: 'upcoming', label: 'Upcoming', count: sampleAppointments.upcoming.length },
    { key: 'past', label: 'Past', count: sampleAppointments.past.length },
    { key: 'cancelled', label: 'Cancelled', count: sampleAppointments.cancelled.length }
  ];

  const currentAppointments = sampleAppointments[activeTab] || [];

  return (
    <div className="min-h-screen bg-bg-secondary py-8 px-4 pb-40">
      <div className="max-w-4xl mx-auto">
        {/* Header */}
        <div className="flex items-center justify-between mb-8">
          <h1 className="text-2xl font-bold text-text-primary">My Appointments</h1>
          <button 
            className="btn btn-primary px-4 py-2 text-sm"
            onClick={() => navigate('/appointments')}
          >
            Book New Appointment
          </button>
        </div>

        {/* Tabs */}
        <div className="bg-white rounded-lg shadow-sm border mb-6">
          <div className="flex border-b">
            {tabs.map((tab) => (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key)}
                className={`flex-1 px-6 py-4 text-center border-b-2 transition-colors ${
                  activeTab === tab.key
                    ? 'border-blue-500 text-blue-600 font-medium'
                    : 'border-transparent text-gray-600 hover:text-gray-800'
                }`}
              >
                {tab.label} ({tab.count})
              </button>
            ))}
          </div>
        </div>

        {/* Appointment Cards */}
        <div className="space-y-4">
          {currentAppointments.map((appointment) => (
            <div key={appointment.id} className="bg-white rounded-lg shadow-sm border p-6">
              <div className="flex items-start justify-between">
                {/* Left side - Doctor info and details */}
                <div className="flex items-start gap-4 flex-1">
                  {/* Doctor Avatar */}
                  <div className="w-12 h-12 bg-blue-500 rounded-full flex items-center justify-center text-white font-semibold text-sm">
                    {appointment.avatar}
                  </div>
                  
                  {/* Doctor Details */}
                  <div className="flex-1">
                    <h3 className="text-lg font-semibold text-text-primary mb-1">
                      {appointment.doctor}
                    </h3>
                    <p className="text-text-secondary text-sm mb-3">
                      {appointment.specialty}
                    </p>
                    
                    {/* Appointment Info Grid */}
                    <div className="grid grid-cols-2 gap-x-8 gap-y-2 text-sm">
                      <div>
                        <span className="text-text-secondary">Date:</span>
                        <div className="font-medium text-text-primary">{appointment.date}</div>
                      </div>
                      <div>
                        <span className="text-text-secondary">Time:</span>
                        <div className="font-medium text-text-primary">{appointment.time}</div>
                      </div>
                      <div>
                        <span className="text-text-secondary">Type:</span>
                        <div className="font-medium text-text-primary">{appointment.type}</div>
                      </div>
                      <div>
                        <span className="text-text-secondary">Booked:</span>
                        <div className="font-medium text-text-primary">{appointment.bookedDate}</div>
                      </div>
                    </div>
                    
                    {appointment.notes && (
                      <div className="mt-3">
                        <span className="text-text-secondary text-sm">Notes:</span>
                        <div className="text-text-primary text-sm">{appointment.notes}</div>
                      </div>
                    )}
                  </div>
                </div>
                
                {/* Right side - Status and Actions */}
                <div className="flex flex-col items-end gap-3">
                  <span className="px-3 py-1 bg-blue-100 text-blue-800 rounded-full text-xs font-medium">
                    {appointment.status}
                  </span>
                  
                  {/* Action Buttons */}
                  {activeTab === 'upcoming' && (
                    <div className="flex gap-2">
                      <button className="px-4 py-2 text-blue-600 border border-blue-600 rounded-lg text-sm hover:bg-blue-50 transition-colors">
                        Reschedule
                      </button>
                      <button className="px-4 py-2 text-red-600 border border-red-600 rounded-lg text-sm hover:bg-red-50 transition-colors">
                        Cancel
                      </button>
                    </div>
                  )}
                  
                  {activeTab === 'past' && (
                    <div className="flex gap-2">
                      <button className="px-4 py-2 text-blue-600 border border-blue-600 rounded-lg text-sm hover:bg-blue-50 transition-colors">
                        Book Again
                      </button>
                      <button className="px-4 py-2 text-gray-600 border border-gray-600 rounded-lg text-sm hover:bg-gray-50 transition-colors">
                        View Report
                      </button>
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Empty State */}
        {currentAppointments.length === 0 && (
          <div className="text-center py-12">
            <div className="text-gray-400 text-6xl mb-4">📅</div>
            <h3 className="text-xl font-medium text-text-primary mb-2">
              No {activeTab} appointments
            </h3>
            <p className="text-text-secondary mb-6">
              {activeTab === 'upcoming' && "You don't have any upcoming appointments scheduled."}
              {activeTab === 'past' && "You haven't had any appointments yet."}
              {activeTab === 'cancelled' && "You don't have any cancelled appointments."}
            </p>
            {activeTab === 'upcoming' && (
              <button 
                className="btn btn-primary"
                onClick={() => navigate('/appointments')}
              >
                Book Your First Appointment
              </button>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default Availability;
